#include<bits/stdc++.h>
using namespace std;
#define endl '\n'
const int maxn=6;
int n,m,flag;
struct node {
	vector< vector<int> > arr;
	int d;//记录次数
};
vector< vector<int> >a,b;
map< vector<vector<int>>,int>mp;
void bfs() {
	queue<node>q;
	q.push({a,0});
	while(!q.empty()) {
		auto t=q.front().arr;
		int d=q.front().d;
		q.pop();
		if(t==b) {
			flag=1;
			cout<<d<<endl;
			return;
		}
		//相邻行的交换
		for(int i=0; i<n-1; i++) {
			swap(t[i],t[i+1]);
			if(!mp.count(t)) {
				q.push({t,d+1}),mp[t]=1;
			}
			swap(t[i],t[i+1]);//撤回
		}
		//相邻列的交换 
		for(int i=0; i<m-1; i++) {
			for(int j=0; j<n; j++) {
				swap(t[j][i],t[j][i+1]);
			}
			if(!mp.count(t)) {
				q.push({t,d+1}),mp[t]=1;
			}
			for(int j=0; j<n; j++) {
				swap(t[j][i],t[j][i+1]);
			}
		}
	}
}
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m;
	a.resize(n);
	for(int i=0; i<n; i++) {
		a[i].resize(m);
		for(int j=0; j<m; j++)
			cin>>a[i][j];
	}
	b.resize(n);
	for(int i=0; i<n; i++) {
		b[i].resize(m);
		for(int j=0; j<m; j++)
			cin>>b[i][j];
	}
	bfs();
	!flag && (cout<<-1);
	return 0;
}
